/**
 * Dependency Graph Analyzer
 *
 * Parses features.json into a DAG and identifies:
 * - Task dependencies
 * - Parallelizable tasks
 * - Execution order (topological sort)
 */

import type { Feature, HarnessConfig } from '../types.js';

export class DependencyGraph {
  private nodes: Map<string, Feature> = new Map();
  private edges: Map<string, Set<string>> = new Map(); // nodeId -> dependents
  private reverseEdges: Map<string, Set<string>> = new Map(); // nodeId -> dependencies

  constructor(config?: HarnessConfig) {
    if (config) {
      this.build(config);
    }
  }

  /**
   * Build the dependency graph from a harness config
   */
  build(config: HarnessConfig): void {
    this.nodes.clear();
    this.edges.clear();
    this.reverseEdges.clear();

    // Add all nodes
    for (const feature of config.features) {
      this.nodes.set(feature.id, feature);
      this.edges.set(feature.id, new Set());
      this.reverseEdges.set(feature.id, new Set());
    }

    // Add edges based on blockedBy
    for (const feature of config.features) {
      const deps = this.getDependencies(feature);
      for (const dep of deps) {
        if (this.nodes.has(dep)) {
          this.edges.get(dep)!.add(feature.id);
          this.reverseEdges.get(feature.id)!.add(dep);
        }
      }
    }
  }

  /**
   * Get normalized dependencies for a feature
   */
  getDependencies(feature: Feature): string[] {
    if (!feature.blockedBy) return [];
    return Array.isArray(feature.blockedBy)
      ? feature.blockedBy
      : [feature.blockedBy];
  }

  /**
   * Get features that are ready to run (no pending dependencies)
   */
  getReadyTasks(): Feature[] {
    const ready: Feature[] = [];

    for (const [id, feature] of this.nodes) {
      if (feature.passes) continue;

      const deps = this.reverseEdges.get(id) || new Set();
      const allDepsComplete = [...deps].every(
        (depId) => this.nodes.get(depId)?.passes === true
      );

      if (allDepsComplete) {
        ready.push(feature);
      }
    }

    return ready;
  }

  /**
   * Get dependents of a task (tasks blocked by it)
   */
  getDependents(taskId: string): string[] {
    return [...(this.edges.get(taskId) || [])];
  }

  /**
   * Topological sort for execution order
   */
  topologicalSort(): string[] {
    const visited = new Set<string>();
    const result: string[] = [];

    const visit = (id: string): void => {
      if (visited.has(id)) return;
      visited.add(id);

      const deps = this.reverseEdges.get(id) || new Set();
      for (const dep of deps) {
        visit(dep);
      }

      result.push(id);
    };

    for (const id of this.nodes.keys()) {
      visit(id);
    }

    return result;
  }

  /**
   * Detect cycles in the graph (which would cause deadlock)
   */
  detectCycles(): string[] | null {
    const visited = new Set<string>();
    const stack = new Set<string>();
    const path: string[] = [];

    const dfs = (id: string): boolean => {
      visited.add(id);
      stack.add(id);
      path.push(id);

      for (const dep of this.reverseEdges.get(id) || []) {
        if (stack.has(dep)) {
          path.push(dep);
          return true;
        }
        if (!visited.has(dep) && dfs(dep)) {
          return true;
        }
      }

      stack.delete(id);
      path.pop();
      return false;
    };

    for (const id of this.nodes.keys()) {
      if (!visited.has(id) && dfs(id)) {
        return path;
      }
    }

    return null;
  }

  /**
   * Get all features
   */
  getAllFeatures(): Feature[] {
    return [...this.nodes.values()];
  }

  /**
   * Get pending features
   */
  getPendingFeatures(): Feature[] {
    return [...this.nodes.values()].filter((f) => !f.passes);
  }

  /**
   * Get a specific feature by ID
   */
  getFeature(id: string): Feature | undefined {
    return this.nodes.get(id);
  }
}

