/**
 * File Lock utility
 *
 * Provides file locking to prevent race conditions
 * when multiple agents update the same file.
 */

import * as lockfile from 'proper-lockfile';
import { existsSync } from 'node:fs';

export interface LockOptions {
  stale?: number; // Time in ms before lock is considered stale
  retries?: number; // Number of retries
  realpath?: boolean; // Resolve symlinks
}

export class FileLock {
  private locks: Map<string, () => Promise<void>> = new Map();

  /**
   * Acquire a lock on a file
   */
  async acquire(filePath: string, options?: LockOptions): Promise<void> {
    if (this.locks.has(filePath)) {
      throw new Error(`Already holding lock on ${filePath}`);
    }

    if (!existsSync(filePath)) {
      throw new Error(`File does not exist: ${filePath}`);
    }

    const release = await lockfile.lock(filePath, {
      stale: options?.stale || 10000,
      retries: options?.retries || 5,
      realpath: options?.realpath ?? false,
    });

    this.locks.set(filePath, release);
  }

  /**
   * Release a lock on a file
   */
  async release(filePath: string): Promise<void> {
    const release = this.locks.get(filePath);
    if (!release) {
      throw new Error(`No lock held on ${filePath}`);
    }

    await release();
    this.locks.delete(filePath);
  }

  /**
   * Execute a function with a file lock
   */
  async withLock<T>(
    filePath: string,
    fn: () => Promise<T>,
    options?: LockOptions
  ): Promise<T> {
    await this.acquire(filePath, options);
    try {
      return await fn();
    } finally {
      await this.release(filePath);
    }
  }

  /**
   * Check if a file is locked
   */
  async isLocked(filePath: string): Promise<boolean> {
    try {
      return await lockfile.check(filePath);
    } catch {
      return false;
    }
  }

  /**
   * Release all held locks
   */
  async releaseAll(): Promise<void> {
    const releases = [...this.locks.entries()];
    for (const [path, release] of releases) {
      try {
        await release();
      } catch {
        // Ignore errors when releasing
      }
      this.locks.delete(path);
    }
  }
}

